53	interface CacheEntry<T> {
54	  data: T;
55	  timestamp: number;
56	}
57	
58	const cache = new Map<string, CacheEntry<unknown>>();
59	
60	function getCacheKey(endpoint: string, params: Record<string, string>): string {
61	  return `${endpoint}?${new URLSearchParams(params).toString()}`;
62	}
63	
64	function getCached<T>(key: string): T | null {
65	  const entry = cache.get(key) as CacheEntry<T> | undefined;
66	  if (!entry) return null;
67	  if (Date.now() - entry.timestamp > wpConfig.cacheTimeout) {
68	    cache.delete(key);
69	    return null;
70	  }
71	  return entry.data;
72	}
73	
74	function setCache<T>(key: string, data: T): void {
75	  cache.set(key, { data, timestamp: Date.now() });
76	}
77	
78	async function wpFetch<T>(endpoint: string, params: Record<string, string> = {}): Promise<T> {
79	  const cacheKey = getCacheKey(endpoint, params);
80	  const cached = getCached<T>(cacheKey);
81	  if (cached) return cached;
82	
83	  const url = new URL(`${getSiteUrl()}${wpConfig.apiBase}${endpoint}`);
84	  Object.entries(params).forEach(([k, v]) => url.searchParams.set(k, v));
85	
86	  const controller = new AbortController();
87	  const timeoutId = setTimeout(() => controller.abort(), 15000);
88	
89	  try {
90	    const res = await fetch(url.toString(), {
91	      headers: { 'Accept': 'application/json' },
92	      signal: controller.signal,
93	    });
94	
95	    clearTimeout(timeoutId);
96	
97	    if (!res.ok) {
98	      throw new Error(`WordPress API error: ${res.status} ${res.statusText} for ${url}`);
99	    }
100	
101	    const data = await res.json() as T;
102	    setCache(cacheKey, data);
103	    return data;
104	  } catch (err) {
105	    clearTimeout(timeoutId);
106	    throw err;
107	  }
108	}
109	
110	async function wpFetchWithHeaders(endpoint: string, params: Record<string, string> = {}): Promise<{ data: unknown; total: number; totalPages: number }> {
111	  const url = new URL(`${getSiteUrl()}${wpConfig.apiBase}${endpoint}`);
112	  Object.entries(params).forEach(([k, v]) => url.searchParams.set(k, v));
113	
114	  const controller = new AbortController();
115	  const timeoutId = setTimeout(() => controller.abort(), 15000);
116	
117	  try {
118	    const res = await fetch(url.toString(), {
119	      headers: { 'Accept': 'application/json' },
120	      signal: controller.signal,
121	    });
122	
123	    clearTimeout(timeoutId);
124	
125	    if (!res.ok) {
126	      throw new Error(`WordPress API error: ${res.status} ${res.statusText} for ${url}`);
127	    }
128	
129	    const total = parseInt(res.headers.get('X-WP-Total') || '0', 10);
130	    const totalPages = parseInt(res.headers.get('X-WP-TotalPages') || '1', 10);
131	    const data = await res.json();
132	    return { data, total, totalPages };
133	  } catch (err) {
134	    clearTimeout(timeoutId);
135	    throw err;
136	  }
137	}
