150	export async function getAllPosts(limitPages = 8): Promise<WPPost[]> {
151	  const perPage = 50;
152	  let totalPages = 1;
153	  try {
154	    const result = await getTotalPosts();
155	    totalPages = result.totalPages;
156	  } catch {
157	    return [];
158	  }
159	
160	  const maxPages = Math.min(totalPages, limitPages);
161	  const allPosts: WPPost[] = [];
162	  const batch = [];
163	
164	  for (let page = 1; page <= maxPages; page++) {
165	    batch.push(getPosts(page, perPage).catch(() => [] as WPPost[]));
166	  }
167	
168	  const results = await Promise.all(batch);
169	  allPosts.push(...results.flat());
170	
171	  return allPosts;
172	}
