17	function stripHtml(html: string | undefined | null): string {
18	  if (!html) return "";
19	  return html
20	    .replace(/<[^>]*>/g, "")
21	    .replace(/&[^;]+;/g, " ")
22	    .trim();
23	}
24	
25	function getFeaturedImage(post: WPPost): string {
26	  const media = post._embedded?.["wp:featuredmedia"];
27	  if (media && media.length > 0 && media[0].source_url) {
28	    return media[0].source_url;
29	  }
30	  const content = post.content?.rendered || "";
31	  const imgMatch = content.match(/<img[^>]+src=["']([^"']+)["']/);
32	  if (imgMatch && imgMatch[1]) {
33	    return imgMatch[1];
34	  }
35	  const excerpt = post.excerpt?.rendered || "";
36	  const excerptImg = excerpt.match(/<img[^>]+src=["']([^"']+)["']/);
37	  if (excerptImg && excerptImg[1]) {
38	    return excerptImg[1];
39	  }
40	  return "";
41	}
