43	function getCategories(post: WPPost): { name: string; slug: string } {
44	  const terms = post._embedded?.["wp:term"];
45	  if (terms && terms[0] && terms[0].length > 0) {
46	    return { name: terms[0][0].name, slug: terms[0][0].slug };
47	  }
48	  return { name: "未分类", slug: "uncategorized" };
49	}
50	
51	function getAuthor(post: WPPost): string {
52	  const authors = post._embedded?.author;
53	  if (authors && authors.length > 0) {
54	    return authors[0].name;
55	  }
56	  return "匿名";
57	}
58	
59	function getTags(post: WPPost): string[] {
60	  const terms = post._embedded?.["wp:term"];
61	  if (terms && terms[1]) {
62	    return terms[1].map((t: { name: string; slug: string }) => t.name);
63	  }
64	  return [];
65	}
66	
67	export function mapPost(post: WPPost): Post {
68	  const cat = getCategories(post);
69	  return {
70	    id: post.id,
71	    title: stripHtml(post.title?.rendered),
72	    excerpt: stripHtml(post.excerpt?.rendered || "").slice(0, 120) + "...",
73	    category: cat.name,
74	    categorySlug: cat.slug,
75	    author: getAuthor(post),
76	    date: post.date,
77	    image: getFeaturedImage(post),
78	    slug: post.slug,
79	    tags: getTags(post),
80	    views: Math.floor(Math.random() * 20000) + 1000,
81	  };
82	}
