107	function pickIcon(name: string, slug: string): string {
108	  const str = name + slug;
109	  let hash = 0;
110	  for (let i = 0; i < str.length; i++) {
111	    hash = (hash << 5) - hash + str.charCodeAt(i);
112	    hash |= 0;
113	  }
114	  return svgIcons[Math.abs(hash) % svgIcons.length];
115	}
