6	export interface SiteData {
7	  posts: Post[];
8	  categories: Array<{ name: string; slug: string; count: number; icon: string }>;
9	  tags: string[];
10	  hotPosts: Post[];
11	  error: string | null;
12	}
13	
14	let cachedSiteData: SiteData | null = null;
15	let cacheTimestamp = 0;
16	
17	export async function fetchSiteData(): Promise<SiteData> {
18	  const now = Date.now();
19	  if (cachedSiteData && now - cacheTimestamp < wpConfig.cacheTimeout) {
20	    return cachedSiteData;
21	  }
22	
23	  try {
24	    const [wpPosts, wpCategories, wpTags] = await Promise.all([
25	      getPosts(1, wpConfig.perPage),
26	      getCategories(),
27	      getTags(),
28	    ]);
29	
30	    const posts = wpPosts.map(mapPost);
31	    const categories = wpCategories.map(mapCategory);
32	    const tags = wpTags.map(mapTag);
33	    const hotPosts = [...posts].sort((a, b) => b.views - a.views).slice(0, 5);
34	
35	    cachedSiteData = { posts, categories, tags, hotPosts, error: null };
36	    cacheTimestamp = now;
37	    return cachedSiteData;
38	  } catch (err) {
39	    console.error('Failed to fetch WordPress data:', err);
40	    const result = {
41	      posts: [],
42	      categories: [],
43	      tags: [],
44	      hotPosts: [],
45	      error: err instanceof Error ? err.message : 'Unknown error',
46	    };
47	    if (cachedSiteData) {
48	      return cachedSiteData;
49	    }
50	    return result;
51	  }
52	}
