2	export async function GET({ url }) {
3	  const siteUrl = process.env.PUBLIC_WP_SITE_URL || 'https://www.frbkw.com';
4	  const page = url.searchParams.get('page') || '1';
5	  const perPage = url.searchParams.get('per_page') || '20';
6	
7	  try {
8	    const response = await fetch(
9	      `${siteUrl}/wp-json/wp/v2/posts?_embed&per_page=${perPage}&page=${page}`
10	    );
11	    const posts = await response.json();
12	
13	    return new Response(JSON.stringify(posts), {
14	      status: 200,
15	      headers: { 'Content-Type': 'application/json' }
16	    });
17	  } catch (error) {
18	    return new Response(JSON.stringify({ error: '获取数据失败' }), {
19	      status: 500,
20	      headers: { 'Content-Type': 'application/json' }
21	    });
22	  }
23	}

