217	<script>
218	  document.addEventListener("DOMContentLoaded", function () {
219	    var content = document.querySelector(".article-content");
220	    if (!content) return;
221	
222	    var imgs = content.querySelectorAll<HTMLImageElement>("img");
223	    imgs.forEach(function (img) {
224	      var src = img.getAttribute("src");
225	      if (src) {
226	        img.setAttribute("data-src", src);
227	        img.removeAttribute("src");
228	        img.style.minHeight = "120px";
229	        img.style.background = "var(--bg-tertiary)";
230	      }
231	    });
232	
233	    var observer = new IntersectionObserver(
234	      function (entries) {
235	        entries.forEach(function (entry) {
236	          if (entry.isIntersecting) {
237	            var img = entry.target as HTMLImageElement;
238	            var dataSrc = img.getAttribute("data-src");
239	            if (dataSrc) {
240	              img.setAttribute("src", dataSrc);
241	              img.removeAttribute("data-src");
242	              img.addEventListener("load", function () {
243	                img.classList.add("img-loaded");
244	                img.style.minHeight = "";
245	                img.style.background = "";
246	              });
247	              img.addEventListener("error", function () {
248	                img.classList.add("img-loaded");
249	                img.style.minHeight = "";
250	                img.style.background = "";
251	              });
252	            }
253	            observer.unobserve(img);
254	          }
255	        });
256	      },
257	      { rootMargin: "300px" },
258	    );
259	
260	    imgs.forEach(function (img) {
261	      observer.observe(img);
262	    });
263	    document.getElementById("goBack").addEventListener("click", () => {
264	      window.history.back();
265	    });
266	
267	    // 代码块：高亮 + 行号 + 语言标识 + 复制按钮
268	    function processCodeBlocks() {
269	    var pres = content.querySelectorAll("pre");
270	    pres.forEach(function (pre) {
271	      var code = pre.querySelector("code");
272	      if (!code) return;
273	
274	      // 检测语言
275	      var lang = "";
276	      var codeClass = code.className || "";
277	      var langMatch = codeClass.match(/language-(\w+)/i) || codeClass.match(/lang-(\w+)/i);
278	      if (langMatch) {
279	        lang = langMatch[1].toLowerCase();
280	      }
281	
282	      // 获取纯文本
283	      var rawText = code.textContent || "";
284	
285	      // highlight.js 高亮
286	      if (typeof hljs !== "undefined") {
287	        if (lang) {
288	          try { hljs.highlightElement(code); } catch(e) {}
289	        } else {
290	          try {
291	            var result = hljs.highlightAuto(rawText);
292	            lang = result.language || "";
293	            code.innerHTML = result.value;
294	          } catch(e) {}
295	        }
296	      }
297	
298	      // 语言显示名映射
299	      var langNames = {
300	        js: "JavaScript", javascript: "JavaScript", ts: "TypeScript", typescript: "TypeScript",
301	        py: "Python", python: "Python", html: "HTML", xml: "XML", css: "CSS",
302	        json: "JSON", bash: "Bash", shell: "Shell", sh: "Shell",
303	        java: "Java", php: "PHP", sql: "SQL", go: "Go", golang: "Go",
304	        rust: "Rust", cpp: "C++", c: "C", cs: "C#", ruby: "Ruby",
305	        swift: "Swift", kotlin: "Kotlin", yaml: "YAML", toml: "TOML",
306	        markdown: "Markdown", md: "Markdown", jsx: "JSX", tsx: "TSX",
307	        vue: "Vue", svelte: "Svelte", dockerfile: "Dockerfile",
308	      };
309	      var displayName = lang ? (langNames[lang] || lang.charAt(0).toUpperCase() + lang.slice(1)) : "Code";
310	
311	      // 构建头部栏
312	      var header = document.createElement("div");
313	      header.className = "code-header";
314	      header.innerHTML =
315	        '<span class="code-lang">' + displayName + '</span>' +
316	        '<button class="code-copy-btn">' +
317	          '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect><path d="M5 15H4a2 2 0 01-2-2V4a2 2 0 012-2h9a2 2 0 012 2v1"></path></svg>' +
318	          '<span>复制</span>' +
319	        '</button>';
320	      pre.insertBefore(header, code);
321	
322	      // 添加行号
323	      var lines = rawText.split("\n");
324	      if (lines[lines.length - 1] === "") lines.pop();
325	      var lineNums = lines.map(function(_, i) {
326	        return '<span class="line-num">' + (i + 1) + '</span>';
327	      }).join("\n");
328	
329	      // 给每行添加行号
330	      var codeLines = code.innerHTML.split("\n");
331	      if (codeLines[codeLines.length - 1] === "") codeLines.pop();
332	      var numberedHTML = codeLines.map(function(line, i) {
333	        return '<span class="line-num">' + (i + 1) + '</span>' + line;
334	      }).join("\n");
335	      code.innerHTML = numberedHTML;
336	
337	      // 复制按钮事件
338	      var copyBtn = header.querySelector(".code-copy-btn");
339	      copyBtn.addEventListener("click", function () {
340	        navigator.clipboard.writeText(rawText).then(function () {
341	          copyBtn.innerHTML =
342	            '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"></polyline></svg>' +
343	            '<span>已复制</span>';
344	          copyBtn.classList.add("copied");
345	          setTimeout(function () {
346	            copyBtn.innerHTML =
347	              '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect><path d="M5 15H4a2 2 0 01-2-2V4a2 2 0 012-2h9a2 2 0 012 2v1"></path></svg>' +
348	              '<span>复制</span>';
349	            copyBtn.classList.remove("copied");
350	          }, 2000);
351	        });
352	      });
353	    });
354	    } // end processCodeBlocks
355	
356	    // 等待 highlight.js 加载完成后处理代码块
357	    function waitForHljs() {
358	      if (typeof hljs !== "undefined") {
359	        processCodeBlocks();
360	      } else {
361	        setTimeout(waitForHljs, 100);
362	      }
363	    }
364	    waitForHljs();
365	  });
