9	const data = await fetchSiteData();
10	const siteData = data.error ? mockData : data;
11	const posts = siteData.posts;
12	const siteFavicon = siteConfig.site.favicon;
13	const siteLogo = siteConfig.site.logo.light;
14	
15	interface MonthGroup {
16	  year: number;
17	  month: number;
18	  label: string;
19	  posts: typeof posts;
20	}
21	
22	const grouped: MonthGroup[] = [];
23	const map = new Map<string, MonthGroup>();
24	
25	const sorted = [...posts].sort(
26	  (a, b) => new Date(b.date).getTime() - new Date(a.date).getTime(),
27	);
28	
29	sorted.forEach((post) => {
30	  const d = new Date(post.date);
31	  const key = `${d.getFullYear()}-${d.getMonth() + 1}`;
32	  if (!map.has(key)) {
33	    const group = {
34	      year: d.getFullYear(),
35	      month: d.getMonth() + 1,
36	      label: `${d.getFullYear()}年${d.getMonth() + 1}月`,
37	      posts: [],
38	    };
39	    map.set(key, group);
40	    grouped.push(group);
41	  }
42	  map.get(key)!.posts.push(post);
43	});
