315	      // 如果图片已经加载完成（缓存），立即显示
316	      if (imageElement.complete && imageElement.naturalWidth > 0) {
317	        imageElement.classList.add('loaded');
318	        if (link) link.classList.add('loaded');
319	        return;
320	      }
321	      
322	      // 加载成功 → 显示图片
323	      imageElement.addEventListener('load', () => {
324	        imageElement.classList.add('loaded');
325	        if (link) link.classList.add('loaded');
326	      });
327	      
328	      // 加载失败 → 保持骨架屏动画（不添加 loaded 类）
329	      imageElement.addEventListener('error', () => {
330	        // 可选：在控制台记录失败图片
331	        console.warn('[图片加载失败]', imageElement.src);
332	        
333	        // 可选：显示错误占位（需要 CSS 配合）
334	        // if (link) link.classList.add('error');
335	      });
336	    });
337	  }
338	
339	  // ===== DOM 就绪后初始化 =====
340	  document.addEventListener('DOMContentLoaded', function () {
341	    // 初始处理所有图片
342	    handleImageLoading();
343	
344	    const BATCH = 12;
345	    const tabs = document.querySelectorAll('#contentTabs a');
346	    const grid = document.getElementById('postGrid') as HTMLElement;
347	    const sentinel = document.getElementById('loadMoreSentinel') as HTMLElement;
348	    const indicator = document.getElementById('loadMoreIndicator') as HTMLElement;
349	    const endMsg = document.getElementById('loadMoreEnd') as HTMLElement;
350	
351	    const revealed: Record<string, number> = {
352	      latest: BATCH,
353	      hot: BATCH,
354	      recommended: BATCH,
355	    };
356	    let currentTab = 'latest';
357	    let loading = false;
358	
359	    function getVisibleItems(): NodeListOf<HTMLElement> {
360	      return grid.querySelectorAll(`.post-item[data-tab="${currentTab}"]`);
361	    }
362	
363	    function getTotal(tab: string): number {
364	      return grid.querySelectorAll(`.post-item[data-tab="${tab}"]`).length;
365	    }
366	
367	    function updateSentinel(): void {
368	      const total = getTotal(currentTab);
369	      if (revealed[currentTab] >= total) {
370	        indicator.style.display = 'none';
371	        endMsg.style.display = total > BATCH ? '' : 'none';
372	      } else {
373	        indicator.style.display = 'none';
374	        endMsg.style.display = 'none';
375	      }
376	    }
377	
378	    function revealMore(): void {
379	      if (loading) return;
380	      const total = getTotal(currentTab);
381	      if (revealed[currentTab] >= total) {
382	        updateSentinel();
383	        return;
384	      }
385	
386	      loading = true;
387	      indicator.style.display = '';
388	
389	      const items = getVisibleItems();
390	      const start = revealed[currentTab];
391	      const end = Math.min(start + BATCH, total);
392	
393	      requestAnimationFrame(() => {
394	        for (let i = start; i < end; i++) {
395	          if (items[i]) {
396	            items[i].style.display = '';
397	          }
398	        }
399	        revealed[currentTab] = end;
400	        loading = false;
401	        indicator.style.display = 'none';
402	        updateSentinel();
403	        
404	        // 新显示的图片需要重新检查加载状态
405	        handleImageLoading();
406	      });
407	    }
408	
409	    // ===== Tab 切换 =====
410	    tabs.forEach((tab) => {
411	      tab.addEventListener('click', function (this: HTMLAnchorElement, e: MouseEvent) {
412	        e.preventDefault();
413	        const target = this.getAttribute('data-tab');
414	        if (!target || target === currentTab) return;
415	
416	        tabs.forEach((t) => t.classList.remove('active'));
417	        this.classList.add('active');
418	
419	        // 隐藏当前 Tab
420	        const oldItems = grid.querySelectorAll(
421	          `.post-item[data-tab="${currentTab}"]`,
422	        );
423	        oldItems.forEach((item) => {
424	          (item as HTMLElement).style.display = 'none';
425	        });
426	
427	        currentTab = target;
428	        endMsg.style.display = 'none';
429	        indicator.style.display = 'none';
430	
431	        // 显示新 Tab
432	        const newItems = getVisibleItems();
433	        newItems.forEach((item, i) => {
434	          item.style.display = i < revealed[currentTab] ? '' : 'none';
435	        });
436	
437	        updateSentinel();
438	        handleImageLoading();
439	      });
440	    });
441	
442	    // ===== 无限滚动 =====
443	    const observer = new IntersectionObserver(
444	      (entries) => {
445	        if (entries[0].isIntersecting) {
446	          revealMore();
447	        }
448	      },
449	      { rootMargin: '200px' },
450	    );
451	
452	    observer.observe(sentinel);
453	    updateSentinel();
454	  });
455	</script>

